import sys

def solve():
    input = sys.stdin.read().split()
    N = int(input[0])
    P = list(map(int, input[1:]))

    ranks = [0] * N
    used = [False] * N
    r = 1

    while True:
        max_score = -1
        indices = []
        for i in range(N):
            if not used[i] and P[i] > max_score:
                max_score = P[i]
                indices = [i]
            elif not used[i] and P[i] == max_score:
                indices.append(i)
        if not indices:
            break
        for i in indices:
            ranks[i] = r
        r += len(indices)

    for rank in ranks:
        print(rank)

if __name__ == "__main__":
    solve()
